export function getQuestionsByCategory(categoryId) {
  return Q.filter(q => q.category === categoryId);
}

export function getQuestionsByDifficulty(difficulty) {
  return Q.filter(q => q.difficulty === difficulty);
}

export function getFilteredQuestions(categoryIds, difficulty) {
  let filtered = Q;
  if (categoryIds && categoryIds.length > 0) {
    filtered = filtered.filter(q => categoryIds.includes(q.category));
  }
  if (difficulty && difficulty !== 'all') {
    filtered = filtered.filter(q => q.difficulty === difficulty);
  }
  return filtered;
}

export function pickRandomQuestions(pool, count) {
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(count, shuffled.length));
}

export default Q;
